<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <v-col cols="12" sm="12" lg="12" class="pa-2">
        <i-card-vertical
          headerTitle="그리드표준 템플릿"
          :useBtnList="buttonUseList"
          @btnAdd="btnAdd()"
          @btnSearch="btnSearch()"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
        >
          <template v-slot:body>
            <!-- 로딩창 -->
            <v-btn @click="showLoadPanel"> 로딩 </v-btn>
            <DxLoadPanel
              :position="position"
              :visible="loadingVisible"
              :show-indicator="showIndicator"
              :show-pane="showPane"
              :shading="false"
              :close-on-outside-click="closeOnOutsideClick"
              :on-shown="onShown"
              shading-color="rgba(0,0,0,0.4)"
              message="조회중..."
            />

            <!-- 팝업 -->
            <v-btn @click="showInfo"> 경고 </v-btn>
            <DxPopup
              :visible="popupVisible"
              :drag-enabled="false"
              :close-on-outside-click="true"
              :show-close-button="false"
              :show-title="false"
              :width="auto"
              :shading="false"
              :height="auto"
              container=".dx-viewport"
            >
              <DxPosition at="center" my="center" :of="positionOf" />
              <DxToolbarItem :visible="closeVisible" widget="dxButton" toolbar="bottom" location="after" :options="closeButtonOptions" />
              <DxToolbarItem :visible="yesVisible" widget="dxButton" toolbar="bottom" location="after" :options="yesButtonOptions" />
              <DxToolbarItem :visible="noVisible" widget="dxButton" toolbar="bottom" location="after" :options="noButtonOptions" />
              <p>
                <span>{{ currentMsg }}</span>
              </p>
            </DxPopup>

            <v-btn @click="dangerClick"> 에러 </v-btn>

            <!-- <v-btn @click="choiceClick"> 선택 </v-btn> -->

            <v-btn @click="showChoice"> 선택 </v-btn>

            <v-layout column layout-col-height0 overflow-auto>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" lg="12" class="mt-2">
                  <DxDataGrid id="gridContainer" :data-source="templateGridTestDataSourece" :remote-operations="true" :show-borders="true">
                    <DxPaging :page-size="15" />

                    <DxColumn data-field="id" width="80" />
                    <DxColumn data-field="title" />
                    <DxMasterDetail :enabled="true" template="master-detail" />
                    <template #master-detail="{ data }">
                      <Advanced-detail-view :master-detail-data="data" />
                    </template>
                  </DxDataGrid>
                </v-col>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
        <!-- <v-btn @click="loadingClick"> 로딩 </v-btn>
        <v-btn @click="warningClick"> 경고 </v-btn>
        <v-btn @click="dangerClick"> 에러 </v-btn>
        <v-btn @click="choiceClick"> 선택 </v-btn> -->
